import mcpi.minecraft as minecraft
import time

mc = minecraft.Minecraft.create()
zones = {
    "Безопасность": (0, 0, 20, 20),
    "Опасность": (21, 0, 40, 20),
}

def inside(pos, x1, z1, x2, z2):
    return x1 <= pos.x <= x2 and z1 <= pos.z <= z2

mc.postToChat("Зоны активны!")
while True:
    pos = mc.player.getTilePos()
    for name, (x1, z1, x2, z2) in zones.items():
        if inside(pos, x1, z1, x2, z2):
            mc.postToChat("Ты в зоне: " + name)
            break
    time.sleep(1)

import mcpi.minecraft as minecraft
import math

mc = minecraft.Minecraft.create()
pos = mc.player.getTilePos()
r = 10
cx, cy, cz = pos.x, pos.y + r + 2, pos.z

for x in range(-r, r+1):
    for y in range(-r, r+1):
        for z in range(-r, r+1):
            if r-1 < math.sqrt(x*x + y*y + z*z) < r:
                mc.setBlock(cx+x, cy+y, cz+z, 20)
mc.postToChat("Сфера готова!")

